import { useEffect, useRef, useState } from "react";
import {
  createBrowserRouter,
  createMemoryRouter,
  Outlet,
  redirect,
  RouterProvider,
} from "react-router-dom";
import Chat from "./pages/DM/Chat";
import Login from "./pages/Auth/Login";
import Register from "./pages/Auth/Register";
import Friends from "./pages/Friends/Friends";
import Loading from "./pages/LoadingScreen/Loading";
import AppLayout from "./components/Layout/AppLayout";
import Sidebar from "./components/Sidebar/Sidebar";
import ServerNav from "./components/ServerNav/ServerNav";
import AddFriend from "./pages/Friends/AddFriend";
import LoginLayout from "./components/Layout/LoginLayout";

const AppContainer = (props) => {
  const [isLoading, setIsLoading] = useState(true);
  const [directMessages, setDirectMessages] = useState([]);
  const [messages, setMessages] = useState([]);
  const ws = useRef(null);

  useEffect(() => {
    console.log("APP FETCHING");
    if (!props.token) {
      setIsLoading(false);
      return;
    }
    const fetchData = async () => {
      try {
        const res = await fetch("/channel/direct-messages", {
          headers: {
            Authorization: "Bearer " + props.token,
          },
        });

        if (res.status !== 200) {
          throw new Error("An error has occurred.");
        }

        const messagesList = await res.json();
        setDirectMessages(messagesList);
      } catch (err) {
        console.log(err);
      } finally {
        setIsLoading(false);
      }
    };

    fetchData();
  }, [props.token]);

  useEffect(() => {
    console.log("APP WEBSOCKET");
    if (!props.userId) {
      return;
    }

    ws.current = new WebSocket(`ws://localhost:8080/?userId=${props.userId}`);

    ws.current.onopen = () => {
      console.log("Connection Open");
      const data = {
        userId: props.userId,
      };
      ws.current.send(JSON.stringify(data));
    };

    ws.current.onmessage = (message) => {
      // Handles notifcation
      console.log("IN APP CONTAINER");
      let data = JSON.parse(message.data);
      console.log(data);
    };

    ws.current.onclose = () => {
      console.log("Connection Closed");
    };
    ws.current.onerror = () => {};

    return () => {
      if (ws.current) {
        ws.current.close();
      }
    };
  }, [props.userId]);

  const sendMessageHandler = (data) => {
    ws.current.send(JSON.stringify(data));
  };

  const storeMessages = (newMessages, chatId) => {
    setMessages((messages) => [
      ...messages,
      { chatId: chatId, messages: newMessages },
    ]);
  };

  const router = createBrowserRouter([
    {
      path: "/",
      loader: () => {
        if (!props.isAuth && !isLoading) return redirect("/login");
        return null;
      },
      element: (
        <AppLayout
          nav={<ServerNav />}
          sidebar={
            <Sidebar
              logoutHandler={props.logoutHandler}
              directMessages={directMessages}
            />
          }
        >
          <Outlet></Outlet>
        </AppLayout>
      ),
      children: [
        {
          path: "/",
          element: <Friends></Friends>,
        },
        {
          path: "/friends",
          element: <Friends></Friends>,
        },
        {
          path: "/online",
          element: <Friends></Friends>,
        },
        {
          path: "/all",
          element: <Friends></Friends>,
        },
        {
          path: "/pending",
          element: <Friends></Friends>,
        },
        {
          path: "/blocked",
          element: <Friends></Friends>,
        },
        {
          path: "/add",
          element: <AddFriend></AddFriend>,
        },
        {
          path: "/:id",
          element: (
            <Chat
              token={props.token}
              sendMessageHandler={sendMessageHandler}
              userId={props.userId}
              storeMessages={storeMessages}
              ws={ws.current}
            ></Chat>
          ),
          loader: ({ params }) => {
            return null;
          },
        },
      ],
    },
    {
      path: "/",
      loader: () => {
        if (props.isAuth && !isLoading) return redirect("/");
        return null;
      },
      element: (
        <LoginLayout>
          <Outlet></Outlet>
        </LoginLayout>
      ),
      children: [
        {
          path: "/login",
          element: <Login loginHandler={props.loginHandler} />,
        },
        {
          path: "/register",
          element: (
            <Register
              registerHandler={props.registerHandler}
              loginHandler={props.loginHandler}
            />
          ),
        },
      ],
    },
  ]);

  if (isLoading) {
    return <Loading></Loading>;
  }

  return <RouterProvider router={router}></RouterProvider>;
};

export default AppContainer;
